# Base geometry module with abstract class
@abstract
class ShapeBase:
    _name: str

    @abstract
    def get_area(self) -> float:
        ...

    @abstract
    def get_name(self) -> str:
        ...

    def __init__(self, name: str):
        self._name = name

def format_area(area: float) -> str:
    return f"{area:.2f}"

